func:
// Seed the run. `channel` picks the target surface (linkedin | reddit | blog);
// blog drafts are markdown-with-frontmatter for the /blog pipeline. `window`
// scopes the harvest. Revision state travels on the message so concurrent runs
// don't clash (flow context would).
msg.channel = (msg.payload && msg.payload.channel) || 'blog';
msg.window = (msg.payload && msg.payload.window) || 'the last 14 days';
msg.revision = 0;
msg.revisionNotes = '';
return msg;

// Carry the digest + its outputRef so the ANGLE step can both read it inline
// and reference it. The entries-search node next overwrites msg.payload with
// past postings, so stash the digest on its own property first.
msg.digest = (msg.result && msg.result.artifactBody) || {};
msg.digestRef = msg.result && msg.result.outputRef;
return msg;

// Lift the chosen angle. If the editor found nothing fresh (angle === null),
// short-circuit to the 'nothing to post' lane — honest cadence over noise.
const body = (msg.result && msg.result.artifactBody) || {};
msg.angle = body.angle || null;
msg.angleRef = msg.result && msg.result.outputRef;
if (msg.angle && Array.isArray(msg.angle.channels) && msg.angle.channels.length) {
  msg.channel = msg.angle.channels[0];
}
msg.hasAngle = msg.angle !== null;
return msg;

// Carry the draft for review + the eventual approval surface. Keep BOTH refs:
// outputRef chains the review/judge tasks; artifactRef points at the remote
// CID-backed artifact (the full blog markdown) for the human to publish.
msg.draftRef = msg.result && msg.result.outputRef;
msg.draftArtifactRef = msg.result && msg.result.artifactRef;
msg.draftSummary = msg.result && msg.result.summary;
msg.draftBody = msg.result && msg.result.artifactBody;
return msg;

// Carry the review so the JUDGE can weigh it and a re-draft can act on it.
msg.review = (msg.result && msg.result.artifactBody) || {};
msg.reviewRef = msg.result && msg.result.outputRef;
return msg;

// The recursion decision. On pass → approval gate. On fail → fold the judge +
// review notes back into the WRITE step and loop, until a revision cap.
const MAX_REVISIONS = 3;
const verdict = (msg.result && msg.result.artifactBody) || {};
msg.verdict = verdict;
if (verdict.pass === true) {
  msg.outcome = 'approved';
  return msg;
}
msg.revision = (msg.revision || 0) + 1;
if (msg.revision > MAX_REVISIONS) {
  msg.outcome = 'gave-up';
  return msg;
}
// Re-draft: point WRITE at the prior draft and hand it the notes to fix.
msg.outcome = 'revise';
msg.priorDraftRef = msg.draftRef;
msg.revisionNotes =
  'Revision ' + msg.revision + ' of ' + MAX_REVISIONS + '.\n' +
  'JUDGE: ' + (verdict.notes || '') + '\n' +
  'REVIEW EDITS: ' + JSON.stringify((msg.review && msg.review.edits) || []);
return msg;
